def normalize_username(value: str) -> str:
    """Return a canonical username."""
    return value.strip()

files.tests/test_text_tools.py:
from src.text_tools import normalize_username


def test_trims_and_lowercases_username():
    assert normalize_username('  Alice.Smith  ') == 'alice.smith'


def test_collapses_internal_whitespace_to_dash():
    assert normalize_username('Ada   Lovelace') == 'ada-lovelace'


def test_rejects_blank_username():
    try:
        normalize_username('   ')
    except ValueError as exc:
        assert 'blank' in str(exc).lower()
    else:
        raise AssertionError('expected ValueError')

