import pytest

from src.invoice import invoice_total


def test_total_uses_quantity_and_rounds_to_cents():
    items = [
        {'price': 12.50, 'quantity': 2},
        {'price': 3.333, 'quantity': 3},
    ]
    assert invoice_total(items, tax_rate=0.0825) == 37.87


def test_missing_quantity_defaults_to_one():
    assert invoice_total([{'price': 4.25}], tax_rate=0) == 4.25


def test_negative_quantity_is_rejected():
    with pytest.raises(ValueError):
        invoice_total([{'price': 2, 'quantity': -1}])
